async fn posts_handler(State(pool): State<PgPool>) -> Result<Json<Value>, AppError> {
    let posts = sqlx::query!("SELECT id, title FROM posts")
        .fetch_all(&pool).await?;

    let ids: Vec<i32> = posts.iter().map(|r| r.id).collect();

    // ONE query instead of N — Postgres array operator
    let comments = sqlx::query!(
        "SELECT post_id, body FROM comments WHERE post_id = ANY($1)",
        &ids as &[i32]
    )
    .fetch_all(&pool).await?;

    let mut grouped: HashMap<i32, Vec<String>> = HashMap::new();
    for c in comments { grouped.entry(c.post_id).or_default().push(c.body); }
    Ok(Json(json!(posts.iter().map(|p| json!({"id": p.id, "comments": grouped.get(&p.id)})).collect::<Vec<_>>())))
}

use axum::{async_trait, extract::FromRequestParts, http::{request::Parts, StatusCode}};
use jsonwebtoken::{decode, DecodingKey, Validation};
use serde::{Deserialize, Serialize};

#[derive(Debug, Serialize, Deserialize)]
pub struct Claims { pub sub: String, pub exp: usize }

#[async_trait]
impl<S: Send + Sync> FromRequestParts<S> for Claims {
    type Rejection = StatusCode;

    async fn from_request_parts(parts: &mut Parts, _state: &S) -> Result<Self, Self::Rejection> {
        let token = parts.headers
            .get("Authorization")
            .and_then(|v| v.to_str().ok())
            .and_then(|s| s.strip_prefix("Bearer "))
            .ok_or(StatusCode::UNAUTHORIZED)?;

        decode::<Claims>(token, &DecodingKey::from_secret(b"secret"), &Validation::default())
            .map(|d| d.claims)
            .map_err(|_| StatusCode::UNAUTHORIZED)
    }
}

